package com.taskmind.backend.task.infrastructure.persistence.jpa; import com.taskmind.backend.task.domain.model.TaskLink; import com.taskmind.backend.task.domain.repository.TaskLinkRepository; import java.util.*; import org.springframework.stereotype.Repository; @Repository public class JpaTaskLinkRepository implements TaskLinkRepository{private final SpringDataTaskLinkJpaRepository repo;public JpaTaskLinkRepository(SpringDataTaskLinkJpaRepository r){repo=r;}public TaskLink save(TaskLink l){return repo.save(TaskLinkJpaEntity.fromDomain(l)).toDomain();}public List<TaskLink> findForTask(UUID id){return repo.findBySourceTaskIdOrTargetTaskId(id,id).stream().map(TaskLinkJpaEntity::toDomain).toList();}public void deleteById(UUID id){repo.deleteById(id);}public Optional<TaskLink> findById(UUID id){return repo.findById(id).map(TaskLinkJpaEntity::toDomain);}}
